// src/App.jsx
import { useState } from "react";
import { AuthProvider, useAuth } from "./hooks/useAuth";
import { Sidebar, Topbar } from "./components/layout/index.jsx";
import { Spinner } from "./components/shared/index.jsx";
import InternLoginPage    from "./components/auth/InternLoginPage.jsx";
import SupervisorLoginPage from "./components/auth/SupervisorLoginPage.jsx";
import ForcedChangePassword from "./components/auth/ForcedChangePassword.jsx";

// Intern pages
import { InternDashboard, MyTasksPage, ProfilePage } from "./pages/intern/index.jsx";
// Supervisor pages
import {
  SupervisorDashboard, AllTasksPage, InternsPage,
  ProjectsPage, MyTasksPageSupervisor,
} from "./pages/supervisor/index.jsx";
// Shared
import ReportPage from "./pages/shared/ReportPage.jsx";

// ── Login router ──────────────────────────────────────────────────────────────
function LoginRouter() {
  const [view, setView] = useState("choose"); // choose | intern | supervisor

  if (view === "intern")     return <InternLoginPage onBack={() => setView("choose")}/>;
  if (view === "supervisor") return <SupervisorLoginPage onBack={() => setView("choose")}/>;

  // Choose screen
  return (
    <div style={{
      minHeight:"100vh", display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"center",
      background:"linear-gradient(145deg,#051a0e 0%,#0a2e1a 40%,#155030 100%)",
      padding:24, gap:32, position:"relative", overflow:"hidden",
    }}>
      <div style={{ position:"absolute", width:500, height:500, borderRadius:"50%", background:"radial-gradient(circle,rgba(46,204,122,.18),transparent 70%)", top:-100, right:-100, pointerEvents:"none" }}/>
      <div style={{ position:"absolute", width:400, height:400, borderRadius:"50%", background:"radial-gradient(circle,rgba(46,204,122,.08),transparent 70%)", bottom:-80, left:-80, pointerEvents:"none" }}/>

      <div style={{ textAlign:"center", zIndex:1 }}>
        <div style={{ fontFamily:"Syne,sans-serif", fontSize:26, fontWeight:900, color:"white", letterSpacing:".3px" }}>Eco Green International</div>
        <div style={{ fontSize:12, color:"rgba(255,255,255,.5)", letterSpacing:"1px", textTransform:"uppercase", marginTop:6 }}>Intern Training Programme 2025 / 2026</div>
      </div>

      <div style={{ display:"flex", gap:20, zIndex:1, flexWrap:"wrap", justifyContent:"center" }}>
        {/* Intern card */}
        <div
          onClick={() => setView("intern")}
          style={{
            background:"rgba(255,255,255,.97)", borderRadius:22, padding:"40px 36px",
            width:280, textAlign:"center", cursor:"pointer",
            boxShadow:"0 24px 80px rgba(0,0,0,.32)", borderTop:"4px solid #2ecc7a",
            transition:"transform .2s,box-shadow .2s",
          }}
          onMouseEnter={e => { e.currentTarget.style.transform="translateY(-4px)"; e.currentTarget.style.boxShadow="0 32px 100px rgba(0,0,0,.4)"; }}
          onMouseLeave={e => { e.currentTarget.style.transform=""; e.currentTarget.style.boxShadow="0 24px 80px rgba(0,0,0,.32)"; }}
        >
          <div style={{ fontSize:48, marginBottom:16 }}>👨‍💻</div>
          <h2 style={{ fontFamily:"Syne,sans-serif", fontSize:22, fontWeight:800, color:"#0a2e1a", marginBottom:8 }}>Intern</h2>
          <p style={{ fontSize:13, color:"#6b7280", marginBottom:20 }}>Access your internship tasks, track hours and view your progress.</p>
          <div style={{ padding:"10px 24px", background:"#2ecc7a", color:"white", borderRadius:10, fontWeight:700, fontSize:13 }}>Sign In →</div>
        </div>

        {/* Supervisor card */}
        <div
          onClick={() => setView("supervisor")}
          style={{
            background:"rgba(255,255,255,.97)", borderRadius:22, padding:"40px 36px",
            width:280, textAlign:"center", cursor:"pointer",
            boxShadow:"0 24px 80px rgba(0,0,0,.32)", borderTop:"4px solid #d4a843",
            transition:"transform .2s,box-shadow .2s",
          }}
          onMouseEnter={e => { e.currentTarget.style.transform="translateY(-4px)"; e.currentTarget.style.boxShadow="0 32px 100px rgba(0,0,0,.4)"; }}
          onMouseLeave={e => { e.currentTarget.style.transform=""; e.currentTarget.style.boxShadow="0 24px 80px rgba(0,0,0,.32)"; }}
        >
          <div style={{ fontSize:48, marginBottom:16 }}>👔</div>
          <h2 style={{ fontFamily:"Syne,sans-serif", fontSize:22, fontWeight:800, color:"#2a1800", marginBottom:8 }}>Supervisor</h2>
          <p style={{ fontSize:13, color:"#6b7280", marginBottom:20 }}>Manage interns, assign tasks and view performance reports.</p>
          <div style={{ padding:"10px 24px", background:"#d4a843", color:"white", borderRadius:10, fontWeight:700, fontSize:13 }}>Sign In →</div>
        </div>
      </div>

      <p style={{ color:"rgba(255,255,255,.3)", fontSize:11, zIndex:1 }}>© 2026 Eco Green International Pvt Ltd</p>
    </div>
  );
}

// ── Main app content ──────────────────────────────────────────────────────────
function AppContent() {
  const { user, loading, mustChangePassword } = useAuth();
  const [page, setPage] = useState("dashboard");

  if (loading) return <Spinner/>;
  if (!user)   return <LoginRouter/>;
  if (mustChangePassword) return <ForcedChangePassword/>;

  const renderPage = () => {
    if (user.role === "intern") {
      if (page === "dashboard") return <InternDashboard/>;
      if (page === "mytasks")   return <MyTasksPage/>;
      if (page === "profile")   return <ProfilePage/>;
      if (page === "report")    return <ReportPage/>;
    }
    if (user.role === "supervisor") {
      if (page === "dashboard") return <SupervisorDashboard/>;
      if (page === "tasks")     return <AllTasksPage/>;
      if (page === "mytasks")   return <MyTasksPageSupervisor/>;
      if (page === "interns")   return <InternsPage/>;
      if (page === "projects")  return <ProjectsPage/>;
      if (page === "report")    return <ReportPage/>;
      if (page === "profile")   return <ProfilePage/>;
    }
    return <div style={{ padding:40 }}>Page not found.</div>;
  };

  return (
    <div style={{ display:"flex", minHeight:"100vh", background:"var(--gray-50)" }}>
      <Sidebar page={page} setPage={setPage}/>
      <div style={{ marginLeft:"var(--sidebar-w)", flex:1, display:"flex", flexDirection:"column" }}>
        <Topbar page={page}/>
        <main style={{ flex:1, padding:"28px 32px", maxWidth:1400, width:"100%" }}>
          {renderPage()}
        </main>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <AppContent/>
    </AuthProvider>
  );
}
